// 获取所有输入数据
const items = $input.all().map(item => item.json);

// Step 1: 将数据按照 createtime 排序
items.sort((a, b) => new Date(a.createtime) - new Date(b.createtime));

// Step 2: 过滤掉 procedure_detail_id 为 13 的数据
const filteredItems = items.filter(item => item.procedure_detail_id !== 13);
console.log("Filtered Items (without procedure_detail_id 13):", filteredItems);

// Step 3: 使用 Map 来组织数据，以便根据 retroid_id 管理它们
const retroidMap = new Map();

for (const item of filteredItems) {
  const id = item.retroid_id;

  if (!retroidMap.has(id)) {
    retroidMap.set(id, []);
  }

  retroidMap.get(id).push(item);
}

// Step 4: 过滤出仍然具有绑定数据的 retroid_id
const activeBindings = new Set();

retroidMap.forEach((list, retroidId) => {
  const boundItemIds = new Set();
  const unboundItemIds = new Set();

  for (const obj of list) {
    if (obj.procedure_detail_id === 62) {
      // 收集解绑的 machine_data_id_old
      const oldMachineId = parseInt(obj.data.machine_data_id_old);
      unboundItemIds.add(oldMachineId);
    } else {
      // 收集所有绑定数据的 machine_data_id
      boundItemIds.add(obj.machine_data_id);
    }
  }

  // 如果存在绑定但没有被解绑的记录
  if ([...boundItemIds].some(id => !unboundItemIds.has(id))) {
    activeBindings.add(retroidId);
  }
});

// Step 5: 格式化输出，返回具有活动绑定的 retroid_id
return [...activeBindings].map(id => ({ json: { retroid_id: id }}));

//tag：0 代表未查到绑定数据，tag：1 代表sn存在绑定数据
//tag：2 代表存在绑定数据，但均已解绑


const items = $input.all();

// 1. 过滤空item（检查json是否存在且非空对象）
const nonEmptyItems = items.filter(item => 
  item?.json && Object.keys(item.json).length > 0
);

// 2. 如果全部为空，返回tag:0
if (nonEmptyItems.length === 0) {
  return [{ json: { tag: 0 } }];
}

// 3. 筛选procedure_detail_id≠62的项，并提取sn或retroid
const resultItems = nonEmptyItems
  .filter(item => item.json.procedure_detail_id !== 62)
  .map(item => {
    // 尝试从不同位置获取sn
    const sn = item.json.data?.sn || 
               item.json.data?.data_old?.sn || 
               null;

    // 尝试获取retroid（可能是字符串或数字）
    const retroid = item.json.retroid_id?.toString() || 
                    item.json.data?.retroid_id_old?.toString() || 
                    null;

    return sn || retroid ? { sn, retroid } : null;
  })
  .filter(item => item !== null); // 确保至少有一个有效值

// 4. 根据结果返回
if (resultItems.length > 0) {
  // 返回tag:1和有效数据（去重）
  const uniqueResults = [...new Set(resultItems.map(item => 
    item.sn || item.retroid
  ))];

  return [{ 
    json: { 
      tag: 1,
      result: uniqueResults
    }
  }];
} else {
  // 没有符合条件的有效数据
  return [{ json: { tag: 2 } }];
}

